1	const BASE_PRICE_BY_TYPE: Record<string, number> = {
2	  potion: 40,
3	  amulet: 60,
4	  staff: 80,
5	  sword: 100,
6	  rune: 25,
7	  moonstone: 25,
8	};
9	const RUNE_COMPONENT_TYPES = new Set(["rune", "moonstone"]);
10	const RUNE_COMPONENT_BLOCK_SIZE = 3;
11	const RUNE_COMPONENT_BLOCK_PRICE = 60;
12	
13	const HIGH_ENCHANTMENT_THRESHOLD = 5;
14	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
15	const CURSE_SURCHARGE_RATE = 0.5;
16	
17	const LOYALTY_THRESHOLD_YEARS = 2;
18	const LOYALTY_DISCOUNT_RATE = 0.2;
19	const FOLLOWUP_THRESHOLD_PREVIOUS_QUOTES = 1;
20	const FOLLOWUP_DISCOUNT_RATE = 0.15;
21	
22	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
23	const PROCESSING_FEE = 5;
24	
25	export function claim(_input: unknown): number {
26	  return 400;
27	}
28	
29	export function quote(input: { customer: { yearsWithMHPCO: number }; items: { type: string; enchantment?: number; cursed?: boolean }[]; previousQuoteCount?: number }): number {
30	  const items = input.items;
31	  const countByType: Record<string, number> = {};
32	  for (const item of items) {
33	    countByType[item.type] = (countByType[item.type] ?? 0) + 1;
34	  }
35	  let basePrice = 0;
36	  for (const type of Object.keys(countByType)) {
37	    const count = countByType[type];
38	    const formsRuneBlock = RUNE_COMPONENT_TYPES.has(type) && count === RUNE_COMPONENT_BLOCK_SIZE;
39	    if (formsRuneBlock) {
40	      basePrice += RUNE_COMPONENT_BLOCK_PRICE;
41	    } else {
42	      basePrice += count * BASE_PRICE_BY_TYPE[type];
43	    }
44	  }
45	  let highEnchantmentSurcharges = 0;
46	  let cursedSurcharges = 0;
47	  for (const item of items) {
48	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
49	      highEnchantmentSurcharges += BASE_PRICE_BY_TYPE[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE;
50	    }
51	    if (item.cursed === true) {
52	      cursedSurcharges += BASE_PRICE_BY_TYPE[item.type] * CURSE_SURCHARGE_RATE;
53	    }
54	  }
55	  const firstInsuranceSurcharge = basePrice * FIRST_INSURANCE_SURCHARGE_RATE;
56	  const qualifiesForLoyaltyDiscount = input.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
57	  const loyaltyDiscount = qualifiesForLoyaltyDiscount ? basePrice * LOYALTY_DISCOUNT_RATE : 0;
58	  const qualifiesForFollowUpDiscount = (input.previousQuoteCount ?? 0) >= FOLLOWUP_THRESHOLD_PREVIOUS_QUOTES;
59	  const followUpDiscount = qualifiesForFollowUpDiscount ? basePrice * FOLLOWUP_DISCOUNT_RATE : 0;
60	  const premium = basePrice + cursedSurcharges + highEnchantmentSurcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE;
61	  return Math.ceil(premium);
62	}
